static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k00305CustomTilingData tiling;
    const gert::Shape *inputShape = context->GetInputShape(0);
    const uint32_t N = static_cast<uint32_t>(inputShape->GetOriginShape().GetDim(0));
    const uint32_t C = static_cast<uint32_t>(inputShape->GetOriginShape().GetDim(1));
    const uint32_t L = static_cast<uint32_t>(inputShape->GetOriginShape().GetDim(2));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int *kernelSize = attrs->GetAttrPointer<int>(0);
    const int *stride = attrs->GetAttrPointer<int>(1);
    uint32_t K = static_cast<uint32_t>(*kernelSize);
    uint32_t S = static_cast<uint32_t>(*stride);

    uint32_t L_out = (L - K) / S + 1;
    uint32_t totalLength = N * C * L_out;

    // Each block handles one (N,C) pair => blockDim = N*C
    uint32_t blockDim = N * C;

    // Tiling within a block: process L_out output elements in chunks
    constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024; // conservative
    constexpr uint32_t ALIGN_ELEMS = 64;
    // We need local storage for input slice (size = (tileLen-1)*S + K) and output tile (tileLen)
    // Max elements per tile: assume each tile uses float, so bytes = (2 * tileLen + (tileLen-1)*S + K) * 4
    // Rough: for K=3, S=2, tileLen approx UB_BUDGET/(4*5) ≈ 9600, but we cap to something
    uint32_t tileLen = L_out; // default to whole output if small
    if (L_out > 10000) {
        uint32_t maxTile = (UB_BUDGET_BYTES / 4 - K) / (S + 2); // approximate
        maxTile = (maxTile / ALIGN_ELEMS) * ALIGN_ELEMS;
        if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
        if (maxTile < 64) maxTile = 64;
        tileLen = maxTile > L_out ? L_out : maxTile;
    }

    context->SetBlockDim(blockDim);

    tiling.totalLength = totalLength;
    tiling.inputWidth = L;
    tiling.outputWidth = L_out;
    tiling.kernelSize = K;
    tiling.stride = S;
    tiling.invKernelSize = 1.0f / static_cast<float>(K);
    tiling.tileLength = tileLen;
    tiling.blockDim = blockDim;

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

