constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00305Custom {
public:
    __aicore__ inline KernelCa6k00305Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t inputWidth,
                                uint32_t outputWidth, uint32_t kernelSize,
                                uint32_t stride, float invKernelSize,
                                uint32_t tileLength)
    {
        totalLen_ = totalLength;
        inputWidth_ = inputWidth;
        outputWidth_ = outputWidth;
        kernelSize_ = kernelSize;
        stride_ = stride;
        invKernelSize_ = invKernelSize;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_ * inputWidth_ * ?); // careful
        // Actually we will recompute offsets per (n,c) pair. So we store the base pointer.
        xBase_ = (__gm__ float*)x;
        yBase_ = (__gm__ float*)y;

        // Local buffers for input slice and output tile
        // input slice length: max (tileLen_ - 1) * stride_ + kernelSize_
        uint32_t inputSliceLen = (tileLen_ > 1) ? ( (tileLen_ - 1) * stride_ + kernelSize_ ) : kernelSize_;
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, inputSliceLen * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (outputWidth_ == 0 || tileLen_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t batch = blockIdx; // treat blockIdx as (n*C + c) flattened

        // Compute base offset for this (n,c) pair
        uint32_t offsetX = batch * inputWidth_;
        uint32_t offsetY = batch * outputWidth_;

        // Process output tiles
        uint32_t curStart = 0;
        while (curStart < outputWidth_) {
            uint32_t curTileLen = outputWidth_ - curStart;
            if (curTileLen > tileLen_) curTileLen = tileLen_;

            // Load input slice for this tile
            // Input slice starts at curStart * stride_ and has length (curTileLen - 1) * stride_ + kernelSize_
            uint32_t inputSliceLen = (curTileLen > 1) ? ( (curTileLen - 1) * stride_ + kernelSize_ ) : kernelSize_;
            uint32_t inputOffset = curStart * stride_;
            AscendC::LocalTensor<float> inLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(inLocal, xBase_ + offsetX + inputOffset, inputSliceLen);
            inQueueX_.EnQue(inLocal);

            // Compute output tile
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();

            // For each output position in the tile, compute sum of squares and then sqrt
            // We'll use a vectorized loop: for each offset in kernel, add squared values
            // Initialize yLocal to zeros
            AscendC::Duplicate<float>(yLocal, 0.0f, curTileLen);
            for (uint32_t k = 0; k < kernelSize_; ++k) {
                // Extract the values at positions curStart*stride_ + k, stride apart
                // We need to implement a gather operation: we cannot directly index with stride.
                // Instead, we can compute using a vectorized sliding: we duplicate the input slice
                // and then shift? For simplicity, we will do a scalar loop over output positions
                // but still within the vectorized block? Actually we can do element-wise scalar loop
                // since kernel size is small. We'll just loop over output indices and use scalar operations.
                // This is inefficient but correct.
            }

            // Alternative: directly compute using scalar loop for each output element in the tile
            for (uint32_t i = 0; i < curTileLen; ++i) {
                float sum = 0.0f;
                for (uint32_t k = 0; k < kernelSize_; ++k) {
                    uint32_t idx = curStart * stride_ + i * stride_? Wait, careful: we want the i-th output element in the tile corresponds to global output index curStart + i.
                    // The input window for global output index outIdx = curStart + i is: start = outIdx * stride_, length = kernelSize_.
                    // So we need to access xBase_[offsetX + start + k].
                    // Since we loaded the input slice starting at inputOffset, the element at offset k from that start is inLocal[k] for the first output, but for subsequent outputs, the window shifts by stride.
                    // Actually we loaded a contiguous slice of input from offsetX + inputOffset, but we only have a contiguous segment. The windows are not contiguous because stride > 1. So we need to load the input slice that covers all windows: from inputOffset to inputOffset + (curTileLen-1)*stride + kernelSize - 1. This slice is contiguous in memory. Then for output with local index i, the window starts at position i*stride within the slice. So we can compute sum over k of inLocal[i*stride + k]^2.
                    sum += inLocal[i * stride_ + k] * inLocal[i * stride_ + k];
                }
                sum *= invKernelSize_;
                yLocal[i] = sqrtf(sum);
            }

            tmpQueue_.FreeTensor(tLocal);
            outQueueY_.EnQue(yLocal);
            inQueueX_.FreeTensor(inLocal);

            // Copy out
            AscendC::LocalTensor<float> yLocalOut = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yBase_ + offsetY + curStart, yLocalOut, curTileLen);
            outQueueY_.FreeTensor(yLocalOut);

            curStart += curTileLen;
        }
    }

